import React, { useState, useEffect, useRef } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const chatEndRef = useRef(null);

  useEffect(() => {
    setMessages([
      {
        sender: "ai",
        text: "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?",
      },
    ]);
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  // ✅ Detect mood ONLY if clearly mentioned
  const detectMood = (text) => {
    const lower = text.toLowerCase();

    if (lower.includes("happy") || lower.includes("good") || lower.includes("great"))
      return "happy";
    if (lower.includes("sad") || lower.includes("down") || lower.includes("cry"))
      return "sad";
    if (lower.includes("angry") || lower.includes("mad") || lower.includes("irritated"))
      return "angry";
    if (lower.includes("stress") || lower.includes("anxious") || lower.includes("worried"))
      return "anxious";

    return null; // 🔥 IMPORTANT CHANGE
  };

  const getAIReply = (mood) => {
    switch (mood) {
      case "happy":
        return "That’s wonderful to hear 🌟 What made you feel happy today?";
      case "sad":
        return "I’m really sorry you’re feeling this way 💙 Do you want to talk about what’s bothering you?";
      case "angry":
        return "It sounds like something upset you 😔 Let’s slow down and talk through it.";
      case "anxious":
        return "Feeling anxious can be tough 😟 Take a slow breath with me. What’s making you feel this way?";
      default:
        return "I’m here with you 💜 Take your time. Tell me more about what’s on your mind.";
    }
  };

  // ✅ Save mood ONLY when detected
  const saveMood = (mood) => {
    if (!mood) return; // 🔥 NO MORE NEUTRAL SPAM

    const existing =
      JSON.parse(localStorage.getItem("moodHistory")) || [];

    existing.push({
      mood,
      intensity: Math.floor(Math.random() * 5) + 1,
      time: new Date().toISOString(),
    });

    localStorage.setItem("moodHistory", JSON.stringify(existing));
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    setMessages((prev) => [...prev, userMessage]);

    const mood = detectMood(input);
    saveMood(mood);

    setTimeout(() => {
      const aiReply = {
        sender: "ai",
        text: getAIReply(mood),
      };
      setMessages((prev) => [...prev, aiReply]);
    }, 600);

    setInput("");
  };

  return (
    <div className="chat-page">
      <div className="chat-card">

        <div className="chat-header">
          <span className="brain">🧠</span>
          <h2>AI Mental Health Assistant</h2>
          <p>I’m here to listen. You’re safe here 💙</p>
        </div>

        <div className="chat-body">
          {messages.map((msg, index) => (
            <div key={index} className={`chat-bubble ${msg.sender}`}>
              {msg.text}
            </div>
          ))}
          <div ref={chatEndRef}></div>
        </div>

        <div className="chat-input">
          <input
            type="text"
            placeholder="Type how you feel..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSend()}
          />
          <button onClick={handleSend}>Send</button>
        </div>

      </div>
    </div>
  );
};

export default GeneralChat;
